const task = $json;
const escalationCount = (task.escalation_count || 0) + 1;

// Build escalation message
let severity = task.priority === 'urgent' ? 'URGENT' : 'HIGH PRIORITY';
let message = `${severity} OVERDUE TASK\n`;
message += `Shop: ${task.shop_name}\n`;
message += `Caller: ${task.caller_name || 'Unknown'} (${task.caller_phone || 'no phone'})\n`;
message += `Type: ${task.task_type}\n`;
message += `Notes: ${task.notes || 'N/A'}\n`;
message += `Due: ${task.due_at}\n`;
message += `Escalation #${escalationCount}`;

return {
  json: {
    task_id: task.task_id,
    shop_phone: task.shop_phone,
    sms_from: task.sms_from_number,
    escalation_message: message,
    escalation_count: escalationCount,
    priority: task.priority
  }
};
